"use client";

import { motion, useReducedMotion } from "framer-motion";
import * as React from "react";

export type Step = {
  label: React.ReactNode;
  description?: React.ReactNode;
};

export type StepperProps = React.HTMLAttributes<HTMLDivElement> & {
  steps: Step[];
  /** Zero-based index of the current step. Earlier steps render complete. */
  active: number;
  orientation?: "horizontal" | "vertical";
};

function StepCircle({
  state,
  index,
  reduceMotion,
}: {
  state: "complete" | "active" | "upcoming";
  index: number;
  reduceMotion: boolean | null;
}) {
  const base =
    "relative grid size-9 shrink-0 place-items-center rounded-full border-2 text-sm font-medium [transition:background-color_250ms_ease,border-color_250ms_ease,color_250ms_ease]";
  const tone =
    state === "complete"
      ? "border-primary bg-primary text-primary-foreground"
      : state === "active"
        ? "border-primary bg-background text-foreground"
        : "border-border bg-background text-muted-foreground";
  return (
    <div className={`${base} ${tone}`}>
      {state === "active" && !reduceMotion && (
        <motion.span
          className="absolute inset-0 rounded-full border-2 border-primary"
          initial={{ opacity: 0.6, scale: 1 }}
          animate={{ opacity: 0, scale: 1.5 }}
          transition={{ duration: 1.4, repeat: Number.POSITIVE_INFINITY }}
        />
      )}
      {state === "complete" ? (
        <motion.svg
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth={3}
          strokeLinecap="round"
          strokeLinejoin="round"
          className="size-4"
          aria-hidden="true"
        >
          <motion.path
            d="M5 13l4 4L19 7"
            initial={reduceMotion ? false : { pathLength: 0 }}
            animate={{ pathLength: 1 }}
            transition={{ duration: 0.3, ease: "easeOut" }}
          />
        </motion.svg>
      ) : (
        index + 1
      )}
    </div>
  );
}

const Stepper = React.forwardRef<HTMLDivElement, StepperProps>(
  ({ steps, active, orientation = "horizontal", className, ...props }, ref) => {
    const reduceMotion = useReducedMotion();
    const horizontal = orientation === "horizontal";

    return (
      <div
        ref={ref}
        className={`flex ${horizontal ? "items-start" : "flex-col"} ${
          className ?? ""
        }`}
        {...props}
      >
        {steps.map((step, i) => {
          const state =
            i < active ? "complete" : i === active ? "active" : "upcoming";
          const isLast = i === steps.length - 1;
          const connectorFilled = i < active;
          return (
            <div
              // biome-ignore lint/suspicious/noArrayIndexKey: fixed ordered steps
              key={i}
              className={`flex ${
                horizontal ? "flex-1 flex-col items-center" : "gap-4"
              } ${horizontal && isLast ? "flex-none" : ""}`}
              aria-current={state === "active" ? "step" : undefined}
            >
              <div
                className={`flex ${
                  horizontal ? "w-full items-center" : "flex-col items-center"
                }`}
              >
                <StepCircle
                  state={state}
                  index={i}
                  reduceMotion={reduceMotion}
                />
                {!isLast && (
                  <div
                    className={`relative overflow-hidden bg-border ${
                      horizontal ? "h-0.5 flex-1" : "my-1 w-0.5 flex-1 self-center"
                    }`}
                    style={horizontal ? undefined : { minHeight: 24 }}
                  >
                    <motion.span
                      className={`absolute inset-0 origin-top-left bg-primary ${
                        horizontal ? "origin-left" : "origin-top"
                      }`}
                      initial={false}
                      animate={
                        horizontal
                          ? { scaleX: connectorFilled ? 1 : 0 }
                          : { scaleY: connectorFilled ? 1 : 0 }
                      }
                      transition={
                        reduceMotion
                          ? { duration: 0 }
                          : { type: "spring", stiffness: 260, damping: 30 }
                      }
                    />
                  </div>
                )}
              </div>
              <div
                className={`${
                  horizontal ? "mt-2 text-center" : "pb-6 pt-1"
                }`}
              >
                <div
                  className={`text-sm font-medium ${
                    state === "upcoming"
                      ? "text-muted-foreground"
                      : "text-foreground"
                  }`}
                >
                  {step.label}
                </div>
                {step.description && (
                  <div className="mt-0.5 text-xs text-muted-foreground">
                    {step.description}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    );
  },
);
Stepper.displayName = "Stepper";

export { Stepper };
